# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import json

# RabbitMQ Management API configuration
RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 15672
RABBITMQ_USER = "admin"
RABBITMQ_PASS = "admin"

# Base URL for RabbitMQ Management API
BASE_URL = f"http://{RABBITMQ_HOST}:{RABBITMQ_PORT}/api"

def create_vhost(vhost_name):
    """Create a virtual host"""
    url = f"{BASE_URL}/vhosts/{vhost_name}"
    headers = {'content-type': 'application/json'}
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASS), 
                              headers=headers, data=json.dumps({}))
        if response.status_code == 201:
            print(f"Created vhost: {vhost_name}")
        else:
            print(f"Failed to create vhost {vhost_name}: {response.status_code}")
    except Exception as e:
        print(f"Error creating vhost {vhost_name}: {e}")

def create_user(username, password):
    """Create a user"""
    url = f"{BASE_URL}/users/{username}"
    headers = {'content-type': 'application/json'}
    data = {
        "password": password,
        "tags": ""
    }
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASS), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 201:
            print(f"Created user: {username}")
        else:
            print(f"Failed to create user {username}: {response.status_code}")
    except Exception as e:
        print(f"Error creating user {username}: {e}")

def set_user_permissions(username, vhost_name, configure_permissions, write_permissions, read_permissions):
    """Set user permissions for a virtual host"""
    url = f"{BASE_URL}/permissions/{vhost_name}/{username}"
    headers = {'content-type': 'application/json'}
    data = {
        "configure": configure_permissions,
        "write": write_permissions,
        "read": read_permissions
    }
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASS), 
                              headers=headers, data=json.dumps(data))
        if response.status_code == 204:
            print(f"Set permissions for user {username} on vhost {vhost_name}")
        else:
            print(f"Failed to set permissions for user {username} on vhost {vhost_name}: {response.status_code}")
    except Exception as e:
        print(f"Error setting permissions for user {username}: {e}")

def setup_multi_tenant_environment():
    """Setup multi-tenant RabbitMQ environment"""
    
    # Define applications and their configurations
    applications = [
        {
            "name": "app1",
            "vhost": "/app1-vhost",
            "user": "app1-user",
            "password": "app1-pass",
            "permissions": {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        },
        {
            "name": "app2",
            "vhost": "/app2-vhost",
            "user": "app2-user",
            "password": "app2-pass",
            "permissions": {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        },
        {
            "name": "app3",
            "vhost": "/app3-vhost",
            "user": "app3-user",
            "password": "app3-pass",
            "permissions": {
                "configure": ".*",
                "write": ".*",
                "read": ".*"
            }
        }
    ]
    
    # Create virtual hosts and users
    for app in applications:
        # Create vhost
        create_vhost(app["vhost"])
        
        # Create user
        create_user(app["user"], app["password"])
        
        # Set permissions
        set_user_permissions(app["user"], app["vhost"], 
                           app["permissions"]["configure"],
                           app["permissions"]["write"],
                           app["permissions"]["read"])

if __name__ == "__main__":
    setup_multi_tenant_environment()